INSERT INTO `ordenes_trabajo` VALUES (76, 'R-2023110004', '00000062', 72, 80, NULL, 1, 'en_revision', 'Laptop Lenovo S340-15IIL S/N: MP1SP88T, con cargador original 20V 2.25A S/N:PA-1450-55LL, Ram ADATA 16GB 3200 AD4S320016G22-SGN, M.2 Kingston NV2 1TB 50026B77856908E3.\r\nEquipo al reproducir video se robotiza.', NULL, 'Mantenimiento Preventivo, lubricación de bisagras, renovación pasta térmica thermalgrizzly 14.2 w/mk de conductividad a cpu y pch, se reconstruyo tres bases donde se inserta los pernos *Se realizo test a memoria RAM y CPU no arrojo error, se procedió a probar el equipo reproduciendo videos 02/11/23 hasta 03/11/23 13:20PM. Entregado 3/11/2023 18:25PM*', NULL, NULL, 0.00, 0.00, 80.00, 130.00, 0.00, 130.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-01 13:50:57', NULL, NULL, 1, NULL, NULL, '2023-11-01 13:50:57', '2026-04-25 08:35:40');
