INSERT INTO `ordenes_trabajo` VALUES (78, 'R-2023110006', '00000064', 74, 82, NULL, 1, 'en_revision', 'Laptop DELL CN-0JC5MT-12961, Ventilador suena, revisar parlantes y batería.', NULL, 'Wi-fi no detecta redes, pasta térmica a CPU reseca de baja calidad, termal pad a chipset lo mezclaron con pasta térmica, se analizo batería enviando test en pdf al cliente, se brindo mantenimiento preventivo, renovación pasta térmica arctic mx-4 a procesador con 8.5 w/mk, thermal pad 1.5 mm a chipset marca thermalright con 14.2 w/mk de conductividad térmica  *Entregado 07/11/23*', NULL, NULL, 0.00, 0.00, 20.00, 100.00, 0.00, 100.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-02 16:34:00', NULL, NULL, 1, NULL, NULL, '2023-11-02 16:34:00', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (79, 'R-2023110007', '00000065', 75, 83, NULL, 1, 'en_revision', 'Laptop Asus X555LJ-XX015D, sin cargador.\r\nProblemas en el teclado. ', NULL, 'Se procedió a realizar el Test al teclado con SVOD3, problemas en la membrana.\r\nCambio de teclado nuevo grado A+, mantenimiento preventivo renovación pasta térmica arctic mx-4 8.5 w/mk de conductividad térmica a cpu y gpu. * Se entrego 02/11/23* ', NULL, NULL, 0.00, 0.00, 80.00, 200.00, 0.00, 200.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-02 20:59:54', NULL, NULL, 1, NULL, NULL, '2023-11-02 20:59:54', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (80, 'R-2023110008', '00000066', 76, 84, NULL, 1, 'entregado', 'PlayStation 3 SLIM CECH-2501A, sin cables, sin mando.\r\nEnciende pero no hay imagen, cliente menciona que se apaga en 10 min aproximadamente. Presenta quiñe por mala manipulación al intentar abrir el equipo, placa arqueada.', NULL, 'Se procedió a cambiar integrado deco, el equipo dio imagen pero se apaga en cuestión de minutos, se procedió a realizar reballing a los tres chip, el equipo trabajo por 1 hora, volviendo a la falla de apagarse interrumpidamente, la placa esta arqueada producto del tiempo guardado. *Se cobrara S/70.00* el servicio por los insumos que se usaron para intentar reparar ( bolas de estaño para los tres chip, Flux en pasta , proceso de reballing, thinner, alcohol isopropílico, pasta térmica arctic, thermal pad 2.0 mm. (Se reembolso S/70.00 soles por plin) *Entregado 21/11/23*', NULL, NULL, 0.00, 0.00, 130.00, 280.00, 0.00, 280.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-03 13:57:49', NULL, NULL, 1, NULL, NULL, '2023-11-03 13:57:49', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (81, 'R-2023110009', '00000067', 77, 85, NULL, 1, 'en_revision', 'Laptop Lenovo Ideapad 330-15IKB S/N:PF1G3VQZ, Procesador Core i3 7020U, RAM 4GB, HHD ST1000L035-1RK172, con cargador genérico, mouse inalámbrico.\r\nEquipo presenta problemas de lentitud.', NULL, 'Se procedió a realizar test al HDD, no arrojo errores, en el Jack AC/DC se encontró parte de la punta de un cargador  obstruyendo el funcionamiento.\r\nCambio de HDD por SSD capacidad 240GB, instalación de programas básicos, respaldo de información, mantenimiento preventivo, renovación pasta térmica marca arctic mx-4 y termal pad arctic a pch, memoria RAM de 4GB para que sume un total de 8GB, reconstrucción base de bisagras, cambio de cable del cargador punta fina.*Entregado 13/11/23*\r\n', NULL, NULL, 0.00, 0.00, 150.00, 370.00, 0.00, 370.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-07 16:57:06', NULL, NULL, 1, NULL, NULL, '2023-11-07 16:57:06', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (82, 'R-2023110010', '00000068', 77, 86, NULL, 1, 'en_revision', 'Laptop Samsung  NP-RV510 S/N: ZWNR93EB100872K, con cargador.\r\nRevisar teclado, no funciona algunas teclas.\r\n', NULL, 'Se procedió a revisar el teclado, problemas en la membrana.\r\nCambio de teclado grado A+ (garantía 04 meses), re instalación sistema operativo, mantenimiento preventivo, renovación pasta térmica a procesador marca arctic mx-4 con 8.5 w/mk de conductividad, thermal pad 0.5mm 6.0 w/mk a chipset. *Entregado 13/11/23*', NULL, NULL, 0.00, 0.00, 100.00, 200.00, 0.00, 200.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-07 17:22:38', NULL, NULL, 1, NULL, NULL, '2023-11-07 17:22:38', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (83, 'R-2023110011', '00000069', 78, 87, NULL, 1, 'en_revision', 'Laptop HP 14-CD0009LA S/N:8CG9060XL4, con cargador original y estuche color negro.\r\nProblemas con la batería TF03XL, no carga.', NULL, 'Se analizo batería y su vida útil se encuentra al 9% por de bajo de los valores permitidos.\r\nCambio de batería nueva compatible grado A+(garantía 06 meses), se envió al cliente video del test, se encontró pasta térmica de baja calidad, ventilador obstruido, problemas en la bisagra lado de la pantalla, renovación pasta térmica arctic MX-4 con 8.5 w/mk de conductividad, reconstrucción y lubricación de bisagra, instalación Windows 10 22H2 *Entregado 08/11/23*', NULL, NULL, 0.00, 0.00, 200.00, 360.00, 0.00, 360.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-08 09:37:55', NULL, NULL, 1, NULL, NULL, '2023-11-08 09:37:55', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (84, 'R-2023110012', '0000006A', 79, 88, NULL, 1, 'entregado', 'CPU HP COMPAQ ELITE 8200, sin cables. 2 bancos de RAM  HYPERX 8GB C/U, SSD WD BLUE 250GB.\r\nEnciende con 5 pitidos sin dar imagen.', NULL, 'Se procedió a lavar la placa, se realizo el diagnostico problemas con el chipset. * Equipo entregado 16/11/23*', NULL, NULL, 0.00, 0.00, 280.00, 20.00, 0.00, 20.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-08 11:15:16', NULL, NULL, 1, NULL, NULL, '2023-11-08 11:15:16', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (85, 'R-2023110013', '0000006B', 80, 89, NULL, 1, 'en_revision', 'Laptop Acer Aspire ES1-572-511T S/N:NXGKQAL003649133DF3400, sin cargador.\r\nRevisar teclado, botón encendido.', NULL, 'Teclado se procedió a enviar a garantía para que sea evaluado por el proveedor fecha 13/11/23. \r\nEl teclado no paso proceso de garantía, el proveedor indica que el problema es causado por una mala manipulación.\r\nSe procede a comprar un nuevo teclado en otro proveedor, cliente se le cobrara 50% del valor total a pagar S/50.00. *garantía 02 meses* *Trabajo entregado 01/12/23*', NULL, NULL, 0.00, 0.00, 370.00, 50.00, 0.00, 50.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-08 19:23:01', NULL, NULL, 1, NULL, NULL, '2023-11-08 19:23:01', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (86, 'R-2023110014', '0000006C', 81, 90, NULL, 1, 'en_revision', 'Laptop Lenovo  Yoga Slim 7 14ITL05 S/N:LROEWK0Y, sin cargador.\r\nEquipo enciende y se apaga sin dar imagen.', NULL, 'Se procedió a retirar el polvo y pelusa acumulada para poder limpiar la placa madre, falta descartar con otra tarjeta IO indicator, se brindo mantenimiento correctivo, renovación pasta térmica arctic mx-4 a procesador con 8.5 w/mk de conductividad térmica, se cambio integrado de la tarjeta IO Indicator el cual impedía de que el equipo inicie, garantía por el servicio (04 meses).*Entregado a domicilio 10/11/23*', NULL, NULL, 0.00, 0.00, 200.00, 170.00, 0.00, 170.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-09 11:55:05', NULL, NULL, 1, NULL, NULL, '2023-11-09 11:55:05', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (87, 'R-2023110015', '0000006D', 82, 91, NULL, 1, 'en_revision', 'Laptop Lenovo Yoga 520-14IKB S/N: MP1CSNL8, sin cargador.\r\nEquipo no inicia Windows, realizar respaldo M.2.', NULL, 'Instalación Windows 11 Home SL, programas básicos, respaldo información. *Entregado 09/11/23*', NULL, NULL, 0.00, 0.00, 360.00, 50.00, 0.00, 50.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-09 14:05:20', NULL, NULL, 1, NULL, NULL, '2023-11-09 14:05:20', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (88, 'R-2023110016', '0000006E', 83, 92, NULL, 1, 'en_revision', 'CPU Halion, motherboard ASUS A88XM-A, sin cables.\r\nProblemas en los puertos laterales USB, audio y micrófono.', NULL, 'Cambio de case marca Rainbow r3 RGB incluye dos ventiladores, traslado de componentes, activación Windows 7 profesional, licencia de antivirus por 1 año Eset Internet Security *Entregado a domicilio 10/11/23*', NULL, NULL, 0.00, 0.00, 20.00, 280.00, 0.00, 280.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-09 19:49:19', NULL, NULL, 1, NULL, NULL, '2023-11-09 19:49:19', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (89, 'R-2023110017', '0000006F', 84, 93, NULL, 1, 'en_revision', 'Laptop ASUS X556U-XX003D S/N:G8N0CV00381931D, con estuche color marrón, cargador original  W15-65N1A.\r\nEquipo al iniciar se distorsiona pantalla por unos segundos, no hay audio, al conectar varios pendrive deja de funcionar, revisar red Wi-fi y Ethernet no detecta. Contraseña 6687', NULL, 'Se probo con otra interfaz HDD, ya reconoce el SSD, también hay audio por parlantes y micrófono, se encontró problemas con el ventilador. El detalle de distorsión en la pantalla es problema de la tarjeta lógica, se probo con otra pantalla y no ocurrió lo antes mencionado.  Diagnostico: Cambio de interfaz HDD, cambio de ventilador, cambio pantalla (segunda), cambio de conector ethernet, soporte para HDD. se brindo mantenimiento sin costo adicional renovando pasta térmica marca arctic mx-4 con 8.5 w/mk, se cambio tarjeta wi-fi a 5G *Trabajo entregado 25/11/23*', NULL, NULL, 0.00, 0.00, 50.00, 410.00, 0.00, 410.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-11 12:59:09', NULL, NULL, 1, NULL, NULL, '2023-11-11 12:59:09', '2026-04-25 08:35:40');
