INSERT INTO `ordenes_trabajo` VALUES (91, 'R-2023110019', '00000071', 86, 95, NULL, 1, 'en_revision', 'Laptop Toshiba C645D-SP4143L S/N: PSC34U-00JLM4, sin cargador.\r\nEquipo con problemas de temperatura, no responde puertos USB.', NULL, 'Mantenimiento correctivo, renovación pasta térmica a procesador arctic MX-4 con 8.5 w/mk de conductividad, se re soldó integrado que controla puertos USB. *Trabajo entregado 26/12/23*', NULL, NULL, 0.00, 0.00, 50.00, 100.00, 0.00, 100.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-13 10:53:02', NULL, NULL, 1, NULL, NULL, '2023-11-13 10:53:02', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (92, 'R-2023110020', '00000072', 85, 96, NULL, 1, 'en_revision', 'Laptop Sony PCG-41111U, sin cargador.\r\nEquipo enciende, revisar botón de encendido, ampliar memoria RAM, no funciona batería.', NULL, 'No se puede ampliar RAM, ya cuenta con dos módulos DDR2 de 2GB.\r\nReconstrucción botón de encendido, mantenimiento preventivo renovación thermal pad a chipset 1.0 mm con 6.0 w/mk y pasta térmica  arctic mx-4 8.5 w/mk de conductividad, adaptación de pila RTC. *Trabajo entregado 03/04/24*', NULL, NULL, 0.00, 0.00, 280.00, 100.00, 0.00, 100.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-13 10:57:21', NULL, NULL, 1, NULL, NULL, '2023-11-13 10:57:21', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (93, 'R-2023110021', '00000073', 87, 97, NULL, 1, 'en_revision', 'Cliente indica que tiene falla de funcionamiento. \r\nEstado de entrada: Batería 0% , caja original rayada y en mal estado, vidrio templado quiñado por golpe o caída. \r\nSe procede con la revisión general del equipo, revisión placa (Tarjeta M), revisión Zócalo (Placa), revisión batería, revisión de pantalla, descarte de corto circuito, temperatura normal (comprobada).\r\nDiagnostico: El equipo Xiaomi Redmi 12C con imei: 861462062594585 , no presenta falla alguna.  \r\nConclusión: Se concluye que el equipo no presenta ninguna falla por el cual tenga que ser devuelto o cambiado.\r\nRevisión cubierta por garantía?:  SI.', NULL, 'Recomendaciones: \r\n1.- Cargar el celular hasta que su batería llegue al 100% ( 2H aproximadamente) \r\n2.- No permitir que su batería se encuentre por debajo del 5% ya que perjudica directamente su funcionamiento. \r\n3.- Utilizar su cargador original.', NULL, NULL, 0.00, 0.00, 410.00, 0.00, 0.00, 0.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-16 23:56:25', NULL, NULL, 1, NULL, NULL, '2023-11-16 23:56:25', '2026-04-25 08:35:40');
INSERT INTO `ordenes_trabajo` VALUES (94, 'R-2023110022', '00000074', 54, 98, NULL, 1, 'en_revision', 'DESKTOP Lenovo ThinkCentre M93P, sin cables.\r\nEquipo no enciende.', NULL, 'EL equipo enciende pero con error CMOS, Disco Duro (HDD) dañado no detecta.\r\nCambio de pila RTC 3 voltios, cambio de HDD por SSD 240GB, sistema operativo Windows 10, programas básicos, rack para SSD 2.5 a 3.5 pulgadas. *Entregado 24/11/23*', NULL, NULL, 0.00, 0.00, 250.00, 250.00, 0.00, 250.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-11-18 13:25:07', NULL, NULL, 1, NULL, NULL, '2023-11-18 13:25:07', '2026-04-25 08:35:40');
