INSERT INTO `ordenes_trabajo` VALUES (110, 'R-2023120002', '00000084', 93, 114, NULL, 1, 'en_revision', 'Laptop Asus Vivobook M6500QC S/N: N8N0CX11B504349 Ryzen 7 serie 5000 RTX3050, con cargador original ADP-120VH B 20V 6A 120W.\r\nEquipo no enciende.', NULL, 'Se encontró los componentes térmicos desgastados, Jack DC pin ID roto, problemas en el system charger.\r\nCambio de Jack DC, se actualizo la BIOS a la versión M6400QC.311, reparación system charger, mantenimiento preventivo, renovación pasta térmica thermalgrizzly 14.2 w/mk a CPU y GPU, cambio de thermal pad 0.5mm 14.8 w/mk a VRAM y bobinas. *Trabajo entregado 13/12/23*', NULL, NULL, 0.00, 0.00, 450.00, 600.00, 0.00, 600.00, 1, 'firma', NULL, NULL, 30, NULL, '2023-12-02 11:02:59', NULL, NULL, 1, NULL, NULL, '2023-12-02 11:02:59', '2026-04-25 08:35:40');
