INSERT INTO `wa_plantillas` VALUES (1, 'Equipo listo para recoger', 'reparacion', 'Hola {nombre} ������\n\n¡Tu equipo ya está *listo para recoger* en {empresa}! ������\n\n������ OT: *{codigo_ot}*\n������ Código de consulta: *{codigo_consulta}*\n\nRecuerda traer tu DNI. ¡Te esperamos!', NULL, 1, '2026-04-13 09:17:15');
INSERT INTO `wa_plantillas` VALUES (2, 'Equipo en reparación', 'reparacion', 'Hola {nombre}, tu equipo está siendo reparado en {empresa} ������\n\n������ OT: *{codigo_ot}*\n\nTe avisamos en cuanto esté listo.', NULL, 1, '2026-04-13 09:17:15');
INSERT INTO `wa_plantillas` VALUES (3, 'Presupuesto para aprobación', 'reparacion', 'Hola {nombre} ������\n\nHemos revisado tu equipo en {empresa} y tenemos el presupuesto listo.\n\n������ OT: *{codigo_ot}*\n������ Total: *{total}*\n\nResponde este mensaje para confirmar o coordinar. ¡Gracias!', NULL, 1, '2026-04-13 09:17:15');
INSERT INTO `wa_plantillas` VALUES (4, 'Equipo entregado - Gracias', 'reparacion', '¡Gracias por confiar en {empresa}! ������\n\nTu equipo fue entregado correctamente.\n������ OT: *{codigo_ot}*\n\nRecuerda que cuentas con garantía. ¡Estamos para servirte!', NULL, 1, '2026-04-13 09:17:15');
INSERT INTO `wa_plantillas` VALUES (5, 'Recordatorio de recojo', 'reparacion', 'Hola {nombre}, te recordamos que tu equipo lleva varios días listo en {empresa}.\n\n������ OT: *{codigo_ot}*\n\nPor favor coordina el recojo. ¡Gracias!', NULL, 1, '2026-04-13 09:17:15');
INSERT INTO `wa_plantillas` VALUES (6, 'Consulta estado en línea', 'reparacion', 'Hola {nombre}, puedes consultar el estado de tu reparación en línea con tu código: *{codigo_consulta}* ������', NULL, 1, '2026-04-13 09:17:15');
INSERT INTO `wa_plantillas` VALUES (7, 'Promoción / Oferta especial', 'venta', 'Hola {nombre} ������\n\n{empresa} tiene ofertas especiales para ti. Visítanos o escríbenos para más información. ¡Te esperamos!', NULL, 1, '2026-04-13 09:17:15');
INSERT INTO `wa_plantillas` VALUES (8, 'Saludo general', 'general', 'Hola {nombre}, gracias por contactar a {empresa} ������ ¿En qué podemos ayudarte hoy?', NULL, 1, '2026-04-13 09:17:15');
